import React from 'react'
import styled from 'styled-components'
import video from './static/prada_2021_menswear_video.webm'
import {Link} from 'react-router-dom'


const BannerVideo = styled.video `
`
const Title = styled.div `
font-size:2.2rem;
color:white;
font-weight:bold;
z-index:2;
`

const Content = styled.p `
font-size:1.5rem;
color:white;
z-index:2;
font-weight:400;
margin:40px 0;
`

const ButtonWrapper = styled.div `
z-index:2;
`

const MensWear = styled(Link) `
border:1px solid white;
padding:21px 40px;
width:18vw;
height:10vh;
text-decoration:none;
background-color:transparent;
border-radius:4px;
font-size:1.2rem;
color:white;
font-weight:800;
&:hover {
	background-color:white;
	cursor:pointer;
	color:#1C1C1C;
}
`

const WomensWear = styled(Link) `
border:1px solid white;
width:18vw;
padding:21px 24px;
margin-left:40px;
height:10vh;
text-decoration:none;
font-weight:800;
background-color:transparent;
border-radius:4px;
font-size:1.2rem;
color:white;
&:hover {
	background-color:white;
	cursor:pointer;
	color:#1C1C1C;
}
`

const Div = styled.div `
overflow:hidden;
width:100vw;
`

const BannerWrapper = styled.div `
position:absolute;
display:flex;
flex-direction:column;
justify-content:center;
align-items:center;
width:100vw;
margin-top:162px;
`

const D = styled.div `
position:relative;
`


export default function Banner () {


	return (
		<D>
			<BannerWrapper>
				<Title>Ultimate Platform for Your Designer Clothing</Title>
				<Content>Start Selling Today</Content>
				<ButtonWrapper>
					<MensWear to='/shop/menswear'>Shop MENSWEAR</MensWear>
					<WomensWear to='/shop/womenswear'>Shop WOMENSWEAR</WomensWear>
				</ButtonWrapper>
			</BannerWrapper>
			<Div>
				<BannerVideo autoPlay={'autoplay'} muted playsinline loop width='100%'>
					<source  src={video}  type='video/webm'/>
				</BannerVideo>
			</Div>
		</D>
	)
}
